  ADD COLUMN IF NOT EXISTS lng      double precision,
  ADD COLUMN IF NOT EXISTS lat      double precision,
  ADD COLUMN IF NOT EXISTS centroid geometry(Point, 4326);

CREATE OR REPLACE FUNCTION features_fill_geom()
RETURNS trigger AS $$
BEGIN
  -- lat/lng berilgan bo'lsa, nuqta geometriyasini yasa
  IF NEW.lng IS NOT NULL AND NEW.lat IS NOT NULL THEN
    NEW.geom := ST_SetSRID(ST_MakePoint(NEW.lng, NEW.lat), 4326);
  END IF;
  -- poligon/chiziq bo'lsa, markazini saqla (tez qidiruv uchun)
  IF NEW.geom IS NOT NULL THEN
    NEW.centroid := ST_Centroid(NEW.geom);
  END IF;
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trg_features_fill_geom
  BEFORE INSERT OR UPDATE ON features
  FOR EACH ROW
  EXECUTE FUNCTION features_fill_geom();

