from pydantic import BaseModel, Field, field_validator

class BBox(BaseModel):
    minx: float = Field(ge=-180, le=180)
    miny: float = Field(ge=-90, le=90)
    maxx: float = Field(ge=-180, le=180)
    maxy: float = Field(ge=-90, le=90)

    @field_validator("maxx")
    @classmethod
    def maxx_after_minx(cls, value, info):
        if "minx" in info.data and value <= info.data["minx"]:
            raise ValueError("maxx must be greater than minx")
        return value

    @field_validator("maxy")
    @classmethod
    def maxy_after_miny(cls, value, info):
        if "miny" in info.data and value <= info.data["miny"]:
            raise ValueError("maxy must be greater than miny")
        return value

