import { useEffect, useMemo, useState } from "react";
import type maplibregl from "maplibre-gl";
import { fetchFeaturesInBBox, type BBox } from "./api";

export function useViewportFeatures(map: maplibregl.Map | null) {
  const [bbox, setBBox] = useState<BBox | null>(null);
  const [state, setState] = useState({ loading: false, error: "", count: 0 });

  useEffect(() => {
    if (!map) return;
    let timer: number | undefined;
    const update = () => {
      window.clearTimeout(timer);
      timer = window.setTimeout(() => {
        const b = map.getBounds();
        setBBox({ minx: b.getWest(), miny: b.getSouth(), maxx: b.getEast(), maxy: b.getNorth() });
      }, 250);
    };
    map.on("moveend", update);
    update();
    return () => {
      window.clearTimeout(timer);
      map.off("moveend", update);
    };
  }, [map]);

  useEffect(() => {
    if (!bbox) return;
    const controller = new AbortController();
    setState((s) => ({ ...s, loading: true, error: "" }));
    fetchFeaturesInBBox(bbox, controller.signal)
      .then((data) => setState({ loading: false, error: "", count: data.features.length }))
      .catch((err) => {
        if (err.name !== "AbortError") setState({ loading: false, error: err.message, count: 0 });
      });
    return () => controller.abort();
  }, [bbox]);

  return useMemo(() => ({ bbox, ...state }), [bbox, state]);
}

