from fastapi import WebSocket

clients: set[WebSocket] = set()

@app.websocket('/ws/detections')
async def ws_detections(ws: WebSocket):
    await ws.accept()
    clients.add(ws)
    try:
        while True:
            await ws.receive_text()   # ping
    finally:
        clients.discard(ws)

async def broadcast(payload: dict):
    dead = []
    for ws in clients:
        try:
            await ws.send_json(payload)
        except Exception:
            dead.append(ws)
    for ws in dead:
        clients.discard(ws)

