def record(result, elapsed):
    LAT.observe(elapsed)
    if not result:
        EMPTY.inc()                # ko'p bo'sh natija -> drift belgisi
    for d in result:
        CONF.observe(d["score"])   # confidence pasayishi -> model eskirgan

